    'dynamodb:PutItem',
    'dynamodb:UpdateItem',
    'dynamodb:DeleteItem',
    'dynamodb:Query',
    'dynamodb:Scan',
  ],
  resources: [table.tableArn],
}));
```

*Key points*: No `dynamodb:*`, no wildcard ARN, encryption enabled by default, and **PITR** protects against accidental data loss.

### 2.3 Security Group – No Open Inbound 0.0.0.0/0  

```typescript
