## 5. Sample **IaC** snippet (AWS CDK – TypeScript) that enforces the recommended IAM posture  

```typescript
import * as cdk from 'aws-cdk-lib';
import { Role, ServicePrincipal, PolicyStatement, Effect } from 'aws-cdk-lib/aws-iam';
import { Vpc, SubnetType, SecurityGroup } from 'aws-cdk-lib/aws-ec2';
import { CfnThing } from 'aws-cdk-lib/aws-iot';

export class SecureIcsStack extends cdk.Stack {
  constructor(scope: cdk.App, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // 1️⃣ VPC with isolated subnets for control‑system devices
    const vpc = new Vpc(this, 'IcsVpc', {
      maxAzs: 2,
      subnetConfiguration: [
        {
          name: 'ControlSubnet',
          subnetType: SubnetType.PRIVATE_ISOLATED,
        },
        {
          name: 'MgmtSubnet',
          subnetType: SubnetType.PRIVATE_WITH_EGRESS,
        },
      ],
    });

    // 2️⃣ Security group – only allow TLS from the management subnet
    const sg = new SecurityGroup(this, 'IcsSg', {
      vpc,
      description: 'Allow TLS only from authorized management hosts',
      allowAllOutbound: false,
    });
    sg.addIngressRule(
      cdk.aws_ec2.Peer.ipv4('10.0.2.0/24'), // MgmtSubnet CIDR
      cdk.aws_ec2.Port.tcp(443),
      'TLS from management subnet'
    );

    // 3️⃣ Least‑privilege role for the device to publish telemetry
    const deviceRole = new Role(this, 'IcsDeviceRole', {
      assumedBy: new ServicePrincipal('iot.amazonaws.com'),
      description: 'Role granted to the IoT device – minimal permissions only',
    });
    deviceRole.addToPolicy(
      new PolicyStatement({
        effect: Effect.ALLOW,
        actions: ['iot:Publish'],
        resources: ['arn:aws:iot:*:*:topic/ics/telemetry'],
        conditions: {
          StringEquals: { 'aws:SourceVpce': vpc.vpcEndpointIds },
        },
      })
    );

    // 4️⃣ Enforce MFA for any human IAM user that can manage the device
    // (this is a policy‑as‑code guardrail, not an inline statement)
    // Use CDK‑Nag / OPA to validate that `aws:MultiFactorAuthPresent` is true
  }
}
```

*The snippet demonstrates how to codify network isolation, TLS‑only access, and a least‑privilege IAM role. It can be extended with **cdk‑nag** or **OPA** policies to enforce MFA and disallow `AdministratorAccess`.*

