### Sample Secure CDK Pattern (TypeScript)

```ts
import * as cdk from 'aws-cdk-lib';
import { Construct } from 'constructs';
import * as lambda from 'aws-cdk-lib/aws-lambda';
import * as iam from 'aws-cdk-lib/aws-iam';

export class SecureLambdaStack extends cdk.Stack {
  constructor(scope: Construct, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // Import an existing Lambda function – do NOT let CDK create a role for it
    const importedFn = lambda.Function.fromFunctionArn(
      this,
      'ImportedFn',
      'arn:aws:lambda:us-east-1:123456789012:function:my-existing-fn'
    );

    // Create a dedicated, least‑privilege execution role
    const execRole = new iam.Role(this, 'ExecRole', {
      assumedBy: new iam.ServicePrincipal('lambda.amazonaws.com'),
      description: 'Least‑privilege role for the imported function',
    });

    // Attach only the permissions the function truly needs
    execRole.addManagedPolicy(
      iam.ManagedPolicy.fromAwsManagedPolicyName('service-role/AWSLambdaBasicExecutionRole')
    );

    // If the function must assume another role, grant a *scoped* PassRole
    const targetRole = iam.Role.fromRoleArn(
      this,
      'TargetRole',
      'arn:aws:iam::123456789012:role/TargetPrivilegedRole'
    );

    execRole.addToPolicy(new iam.PolicyStatement({
      effect: iam.Effect.ALLOW,
      actions: ['iam:PassRole'],
      resources: [targetRole.roleArn],   // **Never** use "*"
    }));

    // Attach the role to the imported function (requires explicit permission)
    // Note: this step is optional – many imported functions already have a role.
    // If you need to replace it, use the low‑level CfnFunction construct:
    const cfnFn = importedFn.node.defaultChild as lambda.CfnFunction;
    cfnFn.role = execRole.roleArn;
  }
}
```

**Key security properties of the pattern**

* **No wildcard `PassRole`.** The only allowed `iam:PassRole` is scoped to a single, known ARN.  
* **Explicit role creation** – the CDK does **not** synthesize a permissive role automatically.  
* **Least‑privilege policies** – only the basic Lambda execution policy is attached; additional permissions are added deliberately.  
* **Auditable** – the role definition lives in source control, making drift detection trivial.

