#### 4.1 Python – Boto3 (S3 PutObject)

```python
import json
import logging
import boto3
import botocore
from tenacity import retry, stop_after_attempt, wait_exponential_jitter

# Structured logger (JSON for CloudWatch)
logger = logging.getLogger(__name__)
handler = logging.StreamHandler()
handler.setFormatter(logging.Formatter(json.dumps({
    "time": "%(asctime)s",
    "level": "%(levelname)s",
    "msg": "%(message)s",
    "request_id": "%(request_id)s"
})))
logger.addHandler(handler)
logger.setLevel(logging.INFO)

s3 = boto3.client('s3')

@retry(stop=stop_after_attempt(5), wait=wait_exponential_jitter())
def put_object(bucket: str, key: str, data: bytes, request_id: str) -> None:
    """Upload data to S3 with explicit error handling."""
    try:
        response = s3.put_object(Bucket=bucket, Key=key, Body=data)
    except botocore.exceptions.ClientError as exc:
        # Log full error context
        logger.error(
            "S3PutObjectFailed",
            extra={
                "request_id": request_id,
                "bucket": bucket,
                "key": key,
                "error_code": exc.response["Error"]["Code"],
                "error_msg": exc.response["Error"]["Message"]
            }
        )
        # Propagate as a custom exception for upstream handling
        raise RuntimeError(f"S3 put_object failed: {exc}") from exc

    # Explicit success verification – Boto3 returns HTTPStatusCode in Metadata
    status = response.get("ResponseMetadata", {}).get("HTTPStatusCode")
    if status != 200:
        logger.error(
            "S3PutObjectUnexpectedStatus",
            extra={
                "request_id": request_id,
                "bucket": bucket,
                "key": key,
                "status": status
            }
        )
        raise RuntimeError(f"Unexpected S3 status {status}")

    logger.info(
        "S3PutObjectSuccess",
        extra={"request_id": request_id, "bucket": bucket, "key": key}
    )
```

**Why this is safe**

* **Explicit check** of `HTTPStatusCode` (200) – no reliance on truthiness.  
* **Retry** only for transient errors (network, throttling) via `tenacity`.  
* **Structured logging** includes `request_id` for correlation with CloudTrail.  
* **IAM principle** should have `s3:PutObject` on the specific bucket/key prefix only.

