#### 4.2 TypeScript – AWS CDK (IAM Role Creation)

```ts
import * as cdk from 'aws-cdk-lib';
import { Construct } from 'constructs';
import { Role, ServicePrincipal, PolicyStatement } from 'aws-cdk-lib/aws-iam';
import { awsCloudWatch } from 'aws-cdk-lib';

export class SecureIamStack extends cdk.Stack {
  constructor(scope: Construct, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // Centralised error handling for CDK constructs
    const safeCreateRole = (id: string, principal: ServicePrincipal): Role => {
      try {
        const role = new Role(this, id, {
          assumedBy: principal,
        });
        // Explicitly attach least‑privileged policy
        role.addToPolicy(
          new PolicyStatement({
            actions: ['s3:GetObject'],
            resources: ['arn:aws:s3:::my‑secure‑bucket/*'],
          })
        );
        return role;
      } catch (e) {
        // CDK synth failures surface as exceptions; we log and re‑throw
        new awsCloudWatch.Alarm(this, `${id}CreationFailed`, {
          metric: new awsCloudWatch.Metric({
            namespace: 'CDK/Errors',
            metricName: 'RoleCreationFailure',
            dimensionsMap: { Stack: this.stackName, RoleId: id },
          }),
          threshold: 1,
          evaluationPeriods: 1,
          alarmDescription: `Failed to create IAM Role ${id}: ${e}`,
        });
        // Propagate to halt synthesis – fail‑fast
        throw new Error(`IAM Role creation failed for ${id}: ${e}`);
      }
    };

    // Use the helper – no silent failures
    const lambdaExecRole = safeCreateRole('LambdaExecRole', new ServicePrincipal('lambda.amazonaws.com'));
  }
}
```

**Why this is safe**

* **Try/catch** around CDK construct creation – CDK throws on synthesis errors (e.g., invalid policy).  
* **Explicit least‑privileged policy** (`s3:GetObject` on a specific bucket).  
* **Alarm** emitted to CloudWatch if creation fails, providing telemetry for immediate response.  
* **Fail‑fast** – synthesis aborts, preventing deployment of a partially‑configured stack.

