#### 4.3 Go – AWS SDK v2 (DynamoDB PutItem)

```go
package main

import (
	"context"
	"encoding/json"
	"log"
	"os"
	"time"

	"github.com/aws/aws-sdk-go-v2/aws"
	"github.com/aws/aws-sdk-go-v2/config"
	ddb "github.com/aws/aws-sdk-go-v2/service/dynamodb"
	"github.com/aws/aws-sdk-go-v2/service/dynamodb/types"
	"github.com/cenkalti/backoff/v4"
)

type Item struct {
	ID   string `json:"id"`
	Data string `json:"data"`
}

// structured logger (JSON)
var logger = log.New(os.Stdout, "", 0)

func main() {
	ctx := context.Background()
	cfg, err := config.LoadDefaultConfig(ctx)
	if err != nil {
		logger.Fatalf(`{"msg":"LoadConfigFailed","error":"%v"}`, err)
	}
	client := ddb.NewFromConfig(cfg)

	item := Item{ID: "123", Data: "secure payload"}
	if err := putItemWithRetry(ctx, client, "my-table", item); err != nil {
		logger.Fatalf(`{"msg":"PutItemFailed","error":"%v"}`, err)
	}
	logger.Printf(`{"msg":"PutItemSuccess","id":"%s"}`, item.ID)
}

// putItemWithRetry performs an explicit success check and retries on retryable errors.
func putItemWithRetry(ctx context.Context, client *ddb.Client, table string, itm Item) error {
	operation := func() error {
		av, err := attributevalue.MarshalMap(itm)
		if err != nil {
			return backoff.Permanent(err) // non‑retryable marshalling error
		}
		_, err = client.PutItem(ctx, &ddb.PutItemInput{
			TableName: aws.String(table),
			Item:      av,
			ConditionExpression: aws.String("attribute_not_exists(ID)"), // idempotent guard
		})
		if err != nil {
			var apiErr *types.ConditionalCheckFailedException
			if errors.As(err, &apiErr) {
				// Business‑logic failure – treat as permanent
				return backoff.Permanent(err)
			}
			// For other errors (throttling, network) let backoff retry
			return err
		}
		// Explicit success – PutItem returns no error on success
		return nil
	}

	expBackoff := backoff.NewExponentialBackOff()
	expBackoff.InitialInterval = 500 * time.Millisecond
	expBackoff.MaxElapsedTime = 15 * time.Second

	if err := backoff.Retry(operation, backoff.WithContext(expBackoff, ctx)); err != nil {
		// Log full context for observability
		logger.Printf(`{"msg":"PutItemRetryExhausted","table":"%s","item_id":"%s","error":"%v"}`, table, itm.ID, err)
		return err
	}
	return nil
}
```

**Why this is safe**

* **Explicit error handling** – `PutItem` returns an error only on failure; we treat any non‑nil error as failure.  
* **Retry with exponential back‑off** for transient errors, but **permanent** errors (e.g., conditional check failure) abort retries.  
* **Structured JSON logs** for CloudWatch/ELK ingestion.  
* **IAM policy** for the Lambda/EC2 role should be limited to `dynamodb:PutItem` on the specific table.

