```ts
import { SynthUtils } from '@aws-cdk/assert';
import * as cdk from 'aws-cdk-lib';
import { SecureLambdaStack } from '../lib/secure-lambda-stack';

test('Lambda role does not contain AWSLambda_FullAccess or wildcard iam:PassRole', () => {
  const app = new cdk.App();
