  await s3.send(new CopyObjectCommand({
    Bucket: srcBucket,
    CopySource: `${srcBucket}/${srcKey}`,
    Key: dstKey,
    ServerSideEncryption: 'aws:kms',
    SSEKMSKeyId: process.env.QUARANTINE_KMS_KEY,
    MetadataDirective: 'COPY',
  }));

  // 2️⃣ Delete original (atomic operation)
  await s3.send(new DeleteObjectCommand({ Bucket: srcBucket, Key: srcKey }));

  // 3️⃣ Record incident in DynamoDB (immutable audit trail)
  await ddb.send(new PutItemCommand({
    TableName: process.env.INCIDENT_TABLE,
    Item: {
      IncidentId: { S: `inc-${Date.now()}` },
      Bucket: { S: srcBucket },
      ObjectKey: { S: srcKey },
      QuarantinedKey: { S: dstKey },
      Timestamp: { N: `${Date.now()}` },
    },
    // Use ConditionExpression to avoid duplicate entries (idempotent)
    ConditionExpression: 'attribute_not_exists(IncidentId)',
  }));

  return { statusCode: 200, body: 'Object quarantined' };
};
