## 3. “Secure‑by‑Design” CDK Linter (CI Integration)

Add a **custom ESLint rule** (or a simple Node script) that scans the CDK source tree for any `PolicyStatement` that:

1. Has `actions.includes('*')` **or** `resources.includes('*')`.
2. Calls `addToPrincipalPolicy` / `addToPolicy` **after** a statement with a wildcard has already been added to the same principal (potential merge).
3. Omits an explicit `effect` (defaults to `Allow`).

```javascript
// scripts/check-iam-policies.js
const ts = require('typescript');
const glob = require('glob');
const path = require('path');

function isWildcard(arr) {
  return arr.some((v) => v === '*');
}

function scanFile(file) {
  const source = ts.createSourceFile(
    file,
    require('fs').readFileSync(file, 'utf8'),
    ts.ScriptTarget.ES2020,
    true
  );

  function visit(node) {
    // Look for new iam.PolicyStatement(...)
    if (
      ts.isNewExpression(node) &&
      node.expression.getText() === 'iam.PolicyStatement'
    ) {
      const props = node.arguments?.[0];
      if (props && ts.isObjectLiteralExpression(props)) {
        const actionsProp = props.properties.find(
          (p) => p.name?.getText() === 'actions'
        );
        const resourcesProp = props.properties.find(
          (p) => p.name?.getText() === 'resources'
        );

        const actions = actionsProp && ts.isPropertyAssignment(actionsProp)
          ? eval(actionsProp.initializer.getText())
          : [];
        const resources = resourcesProp && ts.isPropertyAssignment(resourcesProp)
          ? eval(resourcesProp.initializer.getText())
          : [];

        if (isWildcard(actions) || isWildcard(resources)) {
          console.error(
            `⚠️  ${file}:${node.getStart()} – PolicyStatement contains wildcard.`
          );
          process.exitCode = 1;
        }
      }
    }
    ts.forEachChild(node, visit);
  }

  visit(source);
}

// Scan all *.ts files under lib/
glob.sync('lib/**/*.ts').forEach(scanFile);
```

Add to `package.json`:

```json
{
  "scripts": {
    "lint:iam": "node scripts/check-iam-policies.js",
    "pretest": "npm run lint:iam"
  }
}
```

The CI pipeline will now **fail** if any new wildcard policy is introduced.

