### 3.4 CDK Construct for Centralised Randomness (TypeScript)

```typescript
import * as cdk from 'aws-cdk-lib';
import { Construct } from 'constructs';
import * as kms from 'aws-cdk-lib/aws-kms';
import * as lambda from 'aws-cdk-lib/aws-lambda';
import * as iam from 'aws-cdk-lib/aws-iam';

export class SecureRandomLambda extends Construct {
  constructor(scope: Construct, id: string) {
    super(scope, id);

    const key = new kms.Key(this, 'RandomKey', {
      enableKeyRotation: true,
      description: 'Key used solely for generating cryptographically‑secure random bytes',
    });

    const fn = new lambda.Function(this, 'RandomGenerator', {
      runtime: lambda.Runtime.NODEJS_20_X,
      handler: 'index.handler',
      code: lambda.Code.fromInline(`
        const AWS = require('aws-sdk');
        const kms = new AWS.KMS();
        exports.handler = async () => {
          const { Plaintext } = await kms.generateDataKey({
            KeyId: process.env.KEY_ARN,
            KeySpec: 'AES_256',
          }).promise();
          return Buffer.from(Plaintext).toString('base64url');
        };
      `),
      environment: {
        KEY_ARN: key.keyArn,
      },
    });

    // Least‑privilege: only GenerateDataKey* on this key
    fn.addToRolePolicy(new iam.PolicyStatement({
      actions: ['kms:GenerateDataKey*'],
      resources: [key.keyArn],
    }));
  }
}
```

*Why this is safe*: The Lambda can only call `GenerateDataKey*` on the dedicated KMS key. The key rotation policy ensures long‑term entropy freshness.

