using System;
using System.Text.RegularExpressions;
using System.Xml;
using System.Xml.XPath;

public static class SafeXPath
{
    // Whitelist: GUID format (example)
    private static readonly Regex GuidRegex = new(@"^[0-9a-fA-F]{8}\b-[0-9a-fA-F]{4}\b-[0-9a-fA-F]{4}\b-[0-9a-fA-F]{4}\b-[0-9a-fA-F]{12}$",
                                                RegexOptions.Compiled);

    public static XPathNodeIterator Query(string xml, string userGuid)
    {
        // 1️⃣ Validate
        if (!GuidRegex.IsMatch(userGuid))
            throw new ArgumentException("Invalid user identifier");

        // 2️⃣ Secure XML parser (disable DTD)
        var settings = new XmlReaderSettings
        {
            DtdProcessing = DtdProcessing.Prohibit,
            XmlResolver = null // disables external entities
        };

        using var reader = XmlReader.Create(new System.IO.StringReader(xml), settings);
        var doc = new XPathDocument(reader);
        var nav = doc.CreateNavigator();

        // 3️⃣ Parameterized XPath using XPathExpression with variable
        var expr = nav.Compile("/users/user[@id=$uid]/profile");
        expr.SetContext(new XmlNamespaceManager(nav.NameTable)); // if namespaces needed
        expr.SetVariable("uid", userGuid); // safe, already validated

        // 4️⃣ Evaluate
        return nav.Select(expr);
    }
}
