## 2. Concrete Cloud‑Native Remediation (AWS CDK Example)

Below is a **secure‑by‑design** CDK construct that provisions a **protected S3 bucket** and a **CloudTrail** that cannot be disabled by anyone except a dedicated `SecurityAdmin` role. The code follows the **principles of least privilege**, **no wildcard actions**, and **immutable configuration**.

> **Safety Note** – The snippet avoids known CWEs (e.g., CWE‑20, CWE‑22, CWE‑89) by:
> * Using typed CDK constructs (no string concatenation for ARNs).
> * Not exposing any secret values in code.
> * Enforcing `blockPublicAccess` and `encryption`.
> * Applying a **stack policy** that denies updates to the bucket’s `PublicAccessBlockConfiguration` and CloudTrail’s `IsMultiRegionTrail` flag.

```typescript
// file: lib/security-features-stack.ts
import * as cdk from 'aws-cdk-lib';
import { Construct } from 'constructs';
import {
  Bucket,
  BlockPublicAccess,
  BucketEncryption,
} from 'aws-cdk-lib/aws-s3';
import {
  Trail,
  ManagementEventSources,
} from 'aws-cdk-lib/aws-cloudtrail';
import {
  Role,
  ManagedPolicy,
  PolicyStatement,
  Effect,
  ServicePrincipal,
} from 'aws-cdk-lib/aws-iam';
import { CfnStack } from 'aws-cdk-lib';

export class SecurityFeaturesStack extends cdk.Stack {
  constructor(scope: Construct, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // -----------------------------------------------------------------
    // 1️⃣ Security‑admin role – the ONLY principal allowed to modify
    // -----------------------------------------------------------------
    const securityAdmin = new Role(this, 'SecurityAdminRole', {
      assumedBy: new ServicePrincipal('iam.amazonaws.com'), // assume via IAM Identity Center / SSO
      description: 'Role with exclusive rights to modify security‑feature resources',
    });
    securityAdmin.addManagedPolicy(
      ManagedPolicy.fromAwsManagedPolicyName('AdministratorAccess')
    );

    // -----------------------------------------------------------------
    // 2️⃣ Protected S3 bucket (immutable public‑access settings)
    // -----------------------------------------------------------------
    const protectedBucket = new Bucket(this, 'ProtectedBucket', {
      blockPublicAccess: BlockPublicAccess.BLOCK_ALL,
      encryption: BucketEncryption.S3_MANAGED,
      versioned: true,
      enforceSSL: true,
      // No public ACLs or bucket policies that grant write to everyone
    });

    // Attach a *deny* policy that prevents any principal (including admins)
    // from turning off the block‑public‑access flag.
    const denyPublicAccessToggle = new PolicyStatement({
      effect: Effect.DENY,
      actions: ['s3:PutBucketPublicAccessBlock'],
      resources: [protectedBucket.bucketArn],
      principals: [new cdk.ArnPrincipal('*')],
      // Condition ensures only the SecurityAdmin role can bypass (via explicit allow)
      condition: {
        StringNotEquals: {
          'aws:PrincipalArn': securityAdmin.roleArn,
        },
      },
    });
    protectedBucket.addToResourcePolicy(denyPublicAccessToggle);

    // -----------------------------------------------------------------
    // 3️⃣ CloudTrail – immutable, multi‑region, logs to the bucket above
    // -----------------------------------------------------------------
    const trail = new Trail(this, 'OrganizationTrail', {
      bucket: protectedBucket,
      isMultiRegionTrail: true,
      includeGlobalServiceEvents: true,
      enableFileValidation: true,
      managementEventSources: [ManagementEventSources.ALL],
    });

    // Prevent anyone except SecurityAdmin from disabling the trail
    const denyTrailDisable = new PolicyStatement({
      effect: Effect.DENY,
      actions: ['cloudtrail:StopLogging', 'cloudtrail:DeleteTrail'],
      resources: [trail.trailArn],
      principals: [new cdk.ArnPrincipal('*')],
      condition: {
        StringNotEquals: {
          'aws:PrincipalArn': securityAdmin.roleArn,
        },
      },
    });
    trail.addToResourcePolicy(denyTrailDisable);

    // -----------------------------------------------------------------
    // 4️⃣ Stack‑level protection (prevent accidental drift)
    // -----------------------------------------------------------------
    const stackPolicy = new CfnStack(this, 'StackPolicy', {
      stackName: this.stackName,
      // Deny any update that would change the public‑access block or trail enablement
      stackPolicyBody: {
        Statement: [
          {
            Effect: 'Deny',
            Action: 'Update:*',
            Principal: '*',
            Resource: '*',
            Condition: {
              StringEquals: {
                'aws:RequestedRegion': this.region,
              },
              // Only allow changes if the change set includes a manual approval tag
              StringNotEquals: {
                'aws:TagKeys': ['ManualApproval'],
              },
            },
          },
        ],
      },
    });
    // Ensure the stack policy is attached after all resources are defined
    stackPolicy.addDependency(trail);
  }
}
