## 3. Sample Secure Patch (Node.js CDK Project)

Below is a **minimal, security‑focused snippet** that demonstrates how to **disable remote transforms** programmatically and enforce a strict IAM policy for a stack. The code follows OWASP Secure Coding Guidelines and avoids the pitfalls that triggered CVE‑2024‑0016.

```ts
// cdk-app.ts
import * as cdk from 'aws-cdk-lib';
import { Construct } from 'constructs';
import * as iam from 'aws-cdk-lib/aws-iam';
import * as s3 from 'aws-cdk-lib/aws-s3';

// -------------------------------------------------------------------
// Global CDK configuration – enforce secure defaults
// -------------------------------------------------------------------
cdk.Aspects.of(new cdk.App()).add({
  visit(node) {
    // Disallow any Fn::Transform that points to a remote URL
    if (cdk.CfnResource.isCfnResource(node)) {
      const tf = (node as cdk.CfnResource).cfnOptions.transform;
      if (tf && typeof tf === 'string' && tf.startsWith('http')) {
        throw new Error(
          `Remote Fn::Transform detected in ${node.node.path}. ` +
          `Remote transforms are prohibited – set CDK_DISABLE_REMOTE_TRANSFORMS=1.`
        );
      }
    }
  },
});

class SecureStack extends cdk.Stack {
  constructor(scope: Construct, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // -----------------------------------------------------------------
    // Example resource with a tightly scoped execution role
    // -----------------------------------------------------------------
    const bucket = new s3.Bucket(this, 'AppBucket', {
      blockPublicAccess: s3.BlockPublicAccess.BLOCK_ALL,
      encryption: s3.BucketEncryption.S3_MANAGED,
      versioned: true,
    });

    // Least‑privilege role for a Lambda (or any compute) that needs the bucket
    const execRole = new iam.Role(this, 'ExecRole', {
      assumedBy: new iam.ServicePrincipal('lambda.amazonaws.com'),
      // Explicit deny of any IAM actions not listed in the policy
      inlinePolicies: {
        BucketAccess: new iam.PolicyDocument({
          statements: [
            new iam.PolicyStatement({
              actions: ['s3:GetObject', 's3:PutObject'],
              resources: [bucket.bucketArn + '/*'],
            }),
          ],
        }),
      },
    });

    // Attach AWS managed policy for basic Lambda execution (logs only)
    execRole.addManagedPolicy(
      iam.ManagedPolicy.fromAwsManagedPolicyName('service-role/AWSLambdaBasicExecutionRole')
    );
  }
}

// -------------------------------------------------------------------
// App entry point – enforce environment variable at runtime
// -------------------------------------------------------------------
if (process.env.CDK_DISABLE_REMOTE_TRANSFORMS !== '1') {
  console.error(
    'ERROR: CDK_DISABLE_REMOTE_TRANSFORMS is not set to "1". ' +
    'Aborting to prevent remote macro execution.'
  );
  process.exit(1);
}

const app = new cdk.App();
new SecureStack(app, 'SecureStack', {
  // Explicitly set the AWS account/region to avoid accidental cross‑account ops
  env: { account: process.env.CDK_DEFAULT_ACCOUNT, region: process.env.CDK_DEFAULT_REGION },
});
app.synth();
```

