*All resource clients are created **once** inside `SecureInitFacade`. The façade validates configuration, performs a dry‑run permission check, and then exposes only *safe* methods.*

### 3.2 TypeScript (CDK + Lambda)

```ts
// lib/secure-init-facade.ts
import { S3, S3ClientConfig } from '@aws-sdk/client-s3';
import { SecretsManager, SecretsManagerClientConfig } from '@aws-sdk/client-secrets-manager';
import { Logger } from '@aws-lambda-powertools/logger';

export class InitializationError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'InitializationError';
  }
}

/**
 * SecureInitFacade creates and validates AWS SDK clients.
 * It is instantiated once (e.g., at module load time) and never mutated.
 */
export class SecureInitFacade {
  public readonly s3: S3;
  public readonly secrets: SecretsManager;
  private readonly logger = new Logger({ serviceName: 'SecureInitFacade' });

  constructor() {
    // 1️⃣ Explicit credential source – never rely on default chain
    const s3Config: S3ClientConfig = {
      region: process.env.AWS_REGION,
      credentials: {
        accessKeyId: this.requireEnv('AWS_ACCESS_KEY_ID'),
        secretAccessKey: this.requireEnv('AWS_SECRET_ACCESS_KEY'),
        // optional session token for STS‑assumed roles
        sessionToken: process.env.AWS_SESSION_TOKEN,
      },
    };

    // 2️⃣ Fail‑fast if any required env var is missing
    this.s3 = new S3(s3Config);
    this.secrets = new SecretsManager({
      region: process.env.AWS_REGION,
      credentials: s3Config.credentials,
    });

    // 3️⃣ Dry‑run permission check (HeadBucket) – ensures least‑privilege
    this.verifyS3Access()
      .catch((e) => {
        this.logger.error('S3 permission verification failed', { error: e });
        throw new InitializationError('Insufficient S3 permissions');
      });
  }

  private requireEnv(name: string): string {
    const value = process.env[name];
    if (!value) {
      this.logger.error(`Missing required environment variable ${name}`);
      throw new InitializationError(`Missing env var ${name}`);
    }
    return value;
  }

  /** Verify that the role can read the bucket that will be used */
  private async verifyS3Access(): Promise<void> {
    const bucket = this.requireEnv('TARGET_BUCKET');
    await this.s3.headBucket({ Bucket: bucket });
    this.logger.info('S3 bucket access verified', { bucket });
  }

  /** Example safe wrapper – validates key name */
  public async getObject(key: string): Promise<Uint8Array> {
    if (!/^[a-zA-Z0-9._-]+$/.test(key)) {
      throw new Error('Invalid S3 object key');
    }
    const resp = await this.s3.getObject({ Bucket: process.env.TARGET_BUCKET!, Key: key });
    // The SDK returns a stream; convert safely
    const chunks: Uint8Array[] = [];
    for await (const chunk of resp.Body as AsyncIterable<Uint8Array>) {
      chunks.push(chunk);
    }
    return Buffer.concat(chunks);
  }
}

// lib/lambda-handler.ts
import { SecureInitFacade } from './secure-init-facade';
import { APIGatewayProxyEvent, APIGatewayProxyResult } from 'aws-lambda';

const facade = new SecureInitFacade(); // instantiated once per container

export const handler = async (
  event: APIGatewayProxyEvent
): Promise<APIGatewayProxyResult> => {
  try {
    const key = event.pathParameters?.['key'];
    if (!key) {
      return { statusCode: 400, body: JSON.stringify({ error: 'Missing key' }) };
    }
    const data = await facade.getObject(key);
    return {
      statusCode: 200,
      headers: { 'Content-Type': 'application/octet-stream' },
      body: data.toString('base64'),
      isBase64Encoded: true,
    };
  } catch (err) {
    // Structured error logging – telemetry
    console.error('Handler error', { error: err });
    return { statusCode: 500, body: JSON.stringify({ error: 'Internal error' }) };
  }
};
```

**Why this code satisfies the constraints**

* **Secure‑by‑design** – No reliance on the SDK default credential chain; all required env vars are validated before client creation.  
* **Fail‑fast** – Missing env vars or permission failures throw `InitializationError` during module load, preventing any request from reaching business logic.  
* **Immutable clients** – `s3` and `secrets` are `readonly` properties of a class instantiated once.  
* **Guardrails** – `getObject` validates the key format, preventing path‑traversal or injection attacks.  
* **Telemetry** – Structured logs (via Powertools) capture success/failure of initialization and per‑request errors.  
* **Least‑privilege IAM** – See Section 4 for the exact policy.  
* **Testability** – The façade can be unit‑tested by mocking `S3` and asserting that missing env vars raise `InitializationError`.  

