## 2. Secure‑by‑Design CDK Example (TypeScript)

The following CDK stack implements the most critical controls while avoiding common CWEs (e.g., **CWE‑200** – Information Exposure, **CWE‑284** – Improper Access Control). All resources are created with **immutable, least‑privilege configurations** and are **fully auditable**.

```typescript
import * as cdk from 'aws-cdk-lib';
import { Construct } from 'constructs';
import * as s3 from 'aws-cdk-lib/aws-s3';
import * as kms from 'aws-cdk-lib/aws-kms';
import * as iam from 'aws-cdk-lib/aws-iam';
import * as logs from 'aws-cdk-lib/aws-logs';
import * as events from 'aws-cdk-lib/aws-events';
import * as targets from 'aws-cdk-lib/aws-events-targets';
import * as lambda from 'aws-cdk-lib/aws-lambda';
import * as ec2 from 'aws-cdk-lib/aws-ec2';
import * as networkfirewall from 'aws-cdk-lib/aws-networkfirewall';

export class ExfiltrationHardeningStack extends cdk.Stack {
  constructor(scope: Construct, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // -----------------------------------------------------------------
    // 1️⃣ KMS key – used for S3 bucket encryption (CWE‑200 mitigation)
    // -----------------------------------------------------------------
    const dataKey = new kms.Key(this, 'DataEncryptionKey', {
      enableKeyRotation: true,
      description: 'Key for encrypting data at rest in S3 buckets',
      removalPolicy: cdk.RemovalPolicy.RETAIN, // never delete key automatically
    });

    // -----------------------------------------------------------------
    // 2️⃣ Secure S3 bucket – encryption, block public access, TLS only
    // -----------------------------------------------------------------
    const secureBucket = new s3.Bucket(this, 'SecureDataBucket', {
      encryption: s3.BucketEncryption.KMS,
      encryptionKey: dataKey,
      blockPublicAccess: s3.BlockPublicAccess.BLOCK_ALL,
      enforceSSL: true, // forces HTTPS (TLS) – prevents clear‑text exfil
      versioned: true,
      lifecycleRules: [
        {
          abortIncompleteMultipartUploadAfter: cdk.Duration.days(7),
        },
      ],
      // Enable data‑event logging for CloudTrail (required for exfil detection)
      serverAccessLogsPrefix: 'access-logs/',
    });

