      assumedBy: new iam.ServicePrincipal('ec2.amazonaws.com'),
      description: 'Role used by application servers – limited to required bucket prefix',
    });

    // Grant only PutObject on a specific prefix, and only with TLS
    secureBucket.grantPut(appRole, 'app/*');
    appRole.addToPolicy(
      new iam.PolicyStatement({
        actions: ['s3:PutObject'],
        resources: [secureBucket.arnForObjects('app/*')],
        conditions: {
          Bool: { 'aws:SecureTransport': 'true' }, // forces HTTPS
        },
      })
