### 2.3  Enforce Strict Policy Generation in Code

Add **global linting** and **runtime checks** to prevent future regressions.

#### 2.3.1  TypeScript/JavaScript Linter Rule (ESLint custom rule)

Create `eslint-plugin-aws-cdk.js`:

```javascript
module.exports = {
  rules: {
    'no-wildcard-resource-with-action': {
      meta: {
        type: 'problem',
        docs: {
          description: 'Disallow IAM PolicyStatement with wildcard resources and non‑read‑only actions',
          category: 'Security',
          recommended: true,
        },
        schema: [], // no options
      },
      create(context) {
        return {
          NewExpression(node) {
            if (node.callee.type !== 'MemberExpression') return;
            const { object, property } = node.callee;
            if (object.name !== 'iam' || property.name !== 'PolicyStatement') return;

            const arg = node.arguments[0];
            if (!arg || arg.type !== 'ObjectExpression') return;

            const actionsProp = arg.properties.find(p => p.key.name === 'actions');
            const resourcesProp = arg.properties.find(p => p.key.name === 'resources');

            if (!actionsProp || !resourcesProp) return;

            const actions = actionsProp.value.elements?.map(e => e.value) ?? [];
            const resources = resourcesProp.value.elements?.map(e => e.value) ?? [];

            const hasWildcardResource = resources.includes('*');
            const hasWriteAction = actions.some(a => !a.endsWith(':List*') && !a.endsWith(':Get*') && !a.endsWith(':Describe*'));

            if (hasWildcardResource && hasWriteAction) {
              context.report({
                node,
                message: 'PolicyStatement contains wildcard resource with write‑capable actions – this is disallowed.',
              });
            }
          },
        };
      },
    },
  },
};
```

Add to `.eslintrc.js`:

```javascript
module.exports = {
  plugins: ['aws-cdk'],
  rules: {
    'aws-cdk/no-wildcard-resource-with-action': 'error',
  },
};
```

Run `npm run lint` in CI; any violation will fail the build.

#### 2.3.2  Runtime Guard (CDK Construct Wrapper)

Create a helper class `SecurePolicyStatement`:

```typescript
import { PolicyStatement, PolicyStatementProps } from 'aws-cdk-lib/aws-iam';

export class SecurePolicyStatement extends PolicyStatement {
  constructor(props: PolicyStatementProps) {
    // Defensive copy to avoid mutating caller's object
    const safeProps = { ...props };

    // Enforce no wildcard resources with write actions
    const hasWildcard = (safeProps.resources ?? []).some(r => r === '*');
    const writeActions = (safeProps.actions ?? []).filter(a => {
      const lower = a.toLowerCase();
      return !(lower.endsWith(':list*') || lower.endsWith(':get*') || lower.endsWith(':describe*'));
    });

    if (hasWildcard && writeActions.length > 0) {
      throw new Error(
        `SecurePolicyStatement: Refusing to create a statement with wildcard resources (${safeProps.resources}) ` +
        `and write‑capable actions (${writeActions}). Refine the resource ARNs or restrict actions.`,
      );
    }

    super(safeProps);
  }
}
```

Replace all `new iam.PolicyStatement` usages with `new SecurePolicyStatement`. This **fails fast** during synthesis, guaranteeing that no insecure policy reaches CloudFormation.

