## 6. Sample End‑to‑End CDK Pipeline (Secure‑by‑Design)

```ts
import * as cdk from 'aws-cdk-lib';
import { Pipeline } from 'aws-cdk-lib/aws-codepipeline';
import { CodeBuildStep, CodePipelineSource, ShellStep } from 'aws-cdk-lib/pipelines';
import { Bucket } from 'aws-cdk-lib/aws-s3';
import { Role, ManagedPolicy } from 'aws-cdk-lib/aws-iam';

export class SecureSupplyChainStack extends cdk.Stack {
  constructor(scope: cdk.App, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // Immutable SBOM bucket (see §2.1)
    const sbomBucket = new Bucket(this, 'SbomBucket', {
      versioned: true,
      encryption: cdk.aws_s3.BucketEncryption.S3_MANAGED,
      objectLockEnabled: true,
      removalPolicy: cdk.RemovalPolicy.RETAIN,
    });

    // CI role with least‑privilege (see §3)
    const ciRole = new Role(this, 'CiRole', {
      assumedBy: new cdk.aws_iam.ServicePrincipal('codebuild.amazonaws.com'),
    });
    ciRole.addManagedPolicy(ManagedPolicy.fromAwsManagedPolicyName('AmazonS3ReadOnlyAccess'));
    ciRole.addToPolicy(new cdk.aws_iam.PolicyStatement({
      actions: ['ecr:GetAuthorizationToken', 'ecr:BatchGetImage'],
      resources: ['arn:aws:ecr:*:*:repository/approved-repo'],
    }));

    // Pipeline definition
    const pipeline = new Pipeline(this, 'SecurePipeline', {
      pipelineName: 'SecureAppPipeline',
      synth: new ShellStep('Synth', {
        input: CodePipelineSource.gitHub('my-org/secure-app', 'main', {
          authentication: cdk.SecretValue.secretsManager('github-token'),
        }),
        commands: [
          'npm ci',
          'npm run build',
          // Build & sign container image
          'docker build -t 123456789012.dkr.ecr.us-east-1.amazonaws.com/secure-app:${CODEBUILD_RESOLVED_SOURCE_VERSION} .',
          'aws ecr get-login-password | docker login --username AWS --password-stdin 123456789012.dkr.ecr.us-east-1.amazonaws.com',
          'docker push 123456789012.dkr.ecr.us-east-1.amazonaws.com/secure-app:${CODEBUILD_RESOLVED_SOURCE_VERSION}',
          // Generate SBOM (CycloneDX)
          'cyclonedx-bom -o sbom.json',
          // Upload SBOM atomically
          `aws s3 cp sbom.json s3://${sbomBucket.bucketName}/latest.sbom.json --metadata-directive REPLACE`,
          // Verify integrity (see §2.3)
          'node verify-sbom.js',
        ],
        role: ciRole,
      }),
    });

    // Deploy stage (only runs if SBOM verification succeeded)
    pipeline.addStage(new cdk.Stage(this, 'Prod', {
      // Application stack would be added here
    }));
  }
}
```

*Key security properties*:

- **Immutable SBOM bucket** prevents tampering.  
- **CI role** is scoped to only the approved ECR repo and read‑only SBOM bucket.  
- **Verification step** aborts the pipeline on any hash mismatch.  
- **GitHub token** is fetched from Secrets Manager (no hard‑coded secrets).  

