  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "WriteOnlyLogAccess",
      "Effect": "Allow",
      "Action": [
        "logs:CreateLogGroup",
        "logs:CreateLogStream",
        "logs:PutLogEvents"
      ],
