## 3. Example of a Secure Patch Process (AWS CDK Context)

Below is a **template** for a safe, automated remediation that you can adapt to the specific component once you know the exact version to upgrade. The code follows the **Secure‑by‑Design** principles and avoids common CWEs (e.g., CWE‑798 hard‑coded credentials, CWE‑269 improper privilege management).

```typescript
// cdk-remediation.ts
import * as cdk from 'aws-cdk-lib';
import { Construct } from 'constructs';
import * as lambda from 'aws-cdk-lib/aws-lambda';
import * as iam from 'aws-cdk-lib/aws-iam';
import * as logs from 'aws-cdk-lib/aws-logs';

// -------------------------------------------------------------------
// 1️⃣  Define the Lambda with the *fixed* runtime version
// -------------------------------------------------------------------
export class SecureLambdaStack extends cdk.Stack {
  constructor(scope: Construct, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // Use the latest non‑vulnerable runtime (replace with actual version)
    const fn = new lambda.Function(this, 'MySecureFunction', {
      runtime: lambda.Runtime.NODEJS_20_X,   // <-- upgraded runtime
      code: lambda.Code.fromAsset('lambda-code/'), // immutable asset
      handler: 'index.handler',
      // 2️⃣  Enforce least‑privilege execution role
      role: new iam.Role(this, 'LambdaExecRole', {
        assumedBy: new iam.ServicePrincipal('lambda.amazonaws.com'),
        // Minimal permissions – adjust as needed
        inlinePolicies: {
          AllowS3ReadOnly: new iam.PolicyDocument({
            statements: [
              new iam.PolicyStatement({
                actions: ['s3:GetObject'],
                resources: ['arn:aws:s3:::my‑trusted‑bucket/*'],
              }),
            ],
          }),
        },
      }),
      // 3️⃣  Enable structured logging and retention
      logRetention: logs.RetentionDays.ONE_MONTH,
      environment: {
        // No hard‑coded secrets – reference Secrets Manager instead
        CONFIG_BUCKET: 'my‑trusted‑bucket',
      },
    });

    // 4️⃣  Add a CodeSigningConfig (defense‑in‑depth)
    const signingConfig = new lambda.CfnCodeSigningConfig(this, 'SigningConfig', {
      allowedPublishers: {
        signingProfileVersionArns: [
          // ARN of a pre‑approved signing profile
          'arn:aws:signer:us-east-1:123456789012:/signing-profiles/MyProfile/abcd1234',
        ],
      },
      codeSigningPolicies: {
        untrustedArtifactOnDeployment: 'Enforce',
      },
    });

    // Attach the signing config to the function
    (fn.node.defaultChild as lambda.CfnFunction).codeSigningConfigArn =
      signingConfig.attrArn;
  }
}
```

