## 2. Cloud‑Native (AWS CDK) Implementation Blueprint  

Below is a **minimal, production‑grade CDK construct** (TypeScript) that creates a hardened environment for any Moxa NPort devices. The code follows **secure‑by‑design** principles: least‑privilege IAM, immutable infrastructure, and automated remediation hooks. All resources are **region‑agnostic** and can be imported into an existing stack.

```typescript
import * as cdk from 'aws-cdk-lib';
import { Construct } from 'constructs';
import * as ec2 from 'aws-cdk-lib/aws-ec2';
import * as iam from 'aws-cdk-lib/aws-iam';
import * mutualTls from 'aws-cdk-lib/aws-certificatemanager';
import * as logs from 'aws-cdk-lib/aws-logs';
import * as events from 'aws-cdk-lib/aws-events';
import * as targets from 'aws-cdk-lib/aws-events-targets';
import * as lambda from 'aws-cdk-lib/aws-lambda';
import * as secretsmanager from 'aws-cdk-lib/aws-secretsmanager';

export class MoxaNPortSecureEnv extends Construct {
  constructor(scope: Construct, id: string) {
    super(scope, id);

    // 1️⃣ VPC (or import existing)
    const vpc = new ec2.Vpc(this, 'NPortVPC', {
      maxAzs: 2,
      subnetConfiguration: [
        {
          name: 'NPortSubnet',
          subnetType: ec2.SubnetType.PRIVATE_WITH_EGRESS,
          cidrMask: 24,
        },
        {
          name: 'BastionSubnet',
          subnetType: ec2.SubnetType.PUBLIC,
          cidrMask: 24,
        },
      ],
    });

    // 2️⃣ Security Group – least privilege
    const nportSG = new ec2.SecurityGroup(this, 'NPortSG', {
      vpc,
      description: 'Allow only required management traffic to NPort devices',
      allowAllOutbound: false,
    });
    // SSH from bastion only
    nportSG.addIngressRule(
      ec2.Peer.ipv4(vpc.publicSubnets[0].ipv4CidrBlock),
      ec2.Port.tcp(22),
      'SSH from bastion host'
    );
    // Optional: Telnet/Serial‑over‑IP (restrict to PLC subnet)
    nportSG.addIngressRule(
      ec2.Peer.ipv4('10.0.20.0/24'), // PLC subnet placeholder
      ec2.Port.tcpRange(4001, 4005),
      'Serial‑over‑IP from PLCs'
    );

    // 3️⃣ IAM Role for the automated firmware‑upgrade Lambda
    const fwUpgradeRole = new iam.Role(this, 'FwUpgradeRole', {
      assumedBy: new iam.ServicePrincipal('lambda.amazonaws.com'),
      description: 'Role for firmware upgrade automation – least privilege',
    });
    fwUpgradeRole.addManagedPolicy(
      iam.ManagedPolicy.fromAwsManagedPolicyName('service-role/AWSLambdaBasicExecutionRole')
    );
    // Permission to read the secret containing the device password
    const devicePwdSecret = new secretsmanager.Secret(this, 'NPortPassword', {
      generateSecretString: {
        passwordLength: 32,
        excludePunctuation: true,
      },
      rotation: {
        automaticallyAfter: cdk.Duration.days(30),
        // rotation Lambda omitted for brevity – use AWS‑provided template
      },
    });
    devicePwdSecret.grantRead(fwUpgradeRole);

    // 4️⃣ CloudWatch Log Group for device syslog
    const syslogGroup = new logs.LogGroup(this, 'NPortSyslog', {
      retention: logs.RetentionDays.NINETY_DAYS,
      encryptionKey: new kms.Key(this, 'SyslogKey'), // at‑rest encryption
    });

    // 5️⃣ EventBridge rule to auto‑quarantine suspicious IPs
    const suspiciousPattern = {
      logGroupName: syslogGroup.logGroupName,
      filterPattern: logs.FilterPattern.anyTerm('authentication failure', 'buffer overflow', 'unauthorized'),
    };
    const quarantineLambda = new lambda.Function(this, 'QuarantineLambda', {
      runtime: lambda.Runtime.NODEJS_20_X,
      handler: 'index.handler',
      code: lambda.Code.fromInline(`
        const AWS = require('aws-sdk');
        const ec2 = new AWS.EC2();
        exports.handler = async (event) => {
          const ip = event.detail.ip; // extracted by the rule
          const params = {
            GroupId: '${nportSG.securityGroupId}',
            IpPermissions: [{
              IpProtocol: '-1',
              IpRanges: [{ CidrIp: ip + '/32' }],
            }],
          };
          await ec2.revokeSecurityGroupIngress(params).promise();
          return { status: 'revoked', ip };
        };
      `),
      role: fwUpgradeRole,
    });
    new events.Rule(this, 'SuspiciousLogRule', {
      eventPattern: {
        source: ['aws.logs'],
        detailType: ['CloudWatch Logs Insight Result'],
        detail: suspiciousPattern,
      },
      targets: [new targets.LambdaFunction(quarantineLambda)],
    });

    // 6️⃣ Output useful identifiers
    new cdk.CfnOutput(this, 'NPortSubnetIds', {
      value: vpc.privateSubnets.map(s => s.subnetId).join(','),
    });
    new cdk.CfnOutput(this, 'NPortSecurityGroupId', {
      value: nportSG.securityGroupId,
    });
    new cdk.CfnOutput(this, 'DevicePasswordSecretArn', {
      value: devicePwdSecret.secretArn,
    });
  }
}
```

