#### Secure CDK Example – Least‑Privilege IAM Role for EC2

```typescript
import * as cdk from 'aws-cdk-lib';
import { Role, ServicePrincipal, ManagedPolicy, PolicyStatement } from 'aws-cdk-lib/aws-iam';
import { Instance, InstanceType, MachineImage } from 'aws-cdk-lib/aws-ec2';

export class SecureEc2Stack extends cdk.Stack {
  constructor(scope: cdk.App, id: string, props?: cdk.StackProps) {
