## 2. Secure CDK Implementation (TypeScript)

The following CDK snippet demonstrates a **secure, auditable, and policy‑driven** KMS key creation, rotation, and usage for an Amazon RDS instance. All constructs are **type‑checked**, and the code avoids insecure patterns (no hard‑coded secrets, no wildcard IAM actions).

```ts
import * as cdk from 'aws-cdk-lib';
import { Stack, StackProps, Duration } from 'aws-cdk-lib';
import * as kms from 'aws-cdk-lib/aws-kms';
import * as iam from 'aws-cdk-lib/aws-iam';
import * as rds from 'aws-cdk-lib/aws-rds';
import * as secretsmanager from 'aws-cdk-lib/aws-secretsmanager';
import * as logs from 'aws-cdk-lib/aws-logs';
import * as cloudtrail from 'aws-cdk-lib/aws-cloudtrail';
import * as config from 'aws-cdk-lib/aws-config';

export class SecureKeyManagementStack extends Stack {
  constructor(scope: cdk.App, id: string, props?: StackProps) {
    super(scope, id, props);

    // -----------------------------------------------------------------
    // 1️⃣  Create a Customer Managed KMS key with rotation enabled
    // -----------------------------------------------------------------
    const dbKmsKey = new kms.Key(this, 'ProdDbKmsKey', {
      alias: 'alias/prod-db-key',
      description: 'KMS CMK for encrypting production RDS data',
      enableKeyRotation: true,               // ✅ Automatic annual rotation
      removalPolicy: cdk.RemovalPolicy.RETAIN, // Prevent accidental deletion
    });

    // -----------------------------------------------------------------
    // 2️⃣  Restrictive key policy – only the RDS role may use it
    // -----------------------------------------------------------------
    const rdsRole = new iam.Role(this, 'RdsAccessRole', {
      assumedBy: new iam.ServicePrincipal('rds.amazonaws.com'),
    });

    // Grant only the required KMS actions
    dbKmsKey.grantEncryptDecrypt(rdsRole);

    // Add explicit condition to bind usage to this role only
    dbKmsKey.addToResourcePolicy(new iam.PolicyStatement({
      sid: 'AllowRdsRoleUse',
      principals: [new iam.ArnPrincipal(rdsRole.roleArn)],
      actions: [
        'kms:Encrypt',
        'kms:Decrypt',
        'kms:ReEncrypt*',
        'kms:GenerateDataKey*',
        'kms:DescribeKey',
      ],
      resources: ['*'],
      conditions: {
        StringEquals: {
          'aws:SourceAccount': this.account,
        },
      },
    }));

    // -----------------------------------------------------------------
    // 3️⃣  Store DB credentials in Secrets Manager (encrypted with the same CMK)
    // -----------------------------------------------------------------
    const dbCredentials = new secretsmanager.Secret(this, 'ProdDbCredentials', {
      secretName: 'prod-db-credentials',
      encryptionKey: dbKmsKey,               // ✅ Secrets encrypted with the same CMK
      generateSecretString: {
        secretStringTemplate: JSON.stringify({ username: 'dbadmin' }),
        generateStringKey: 'password',
        passwordLength: 32,
        excludePunctuation: true,
      },
      removalPolicy: cdk.RemovalPolicy.RETAIN,
    });

    // -----------------------------------------------------------------
    // 4️⃣  Provision an RDS instance that uses the CMK for storage encryption
    // -----------------------------------------------------------------
    const dbInstance = new rds.DatabaseInstance(this, 'ProdPostgres', {
      engine: rds.DatabaseInstanceEngine.postgres({ version: rds.PostgresEngineVersion.VER_15_4 }),
      instanceType: cdk.aws_ec2.InstanceType.of(
        cdk.aws_ec2.InstanceClass.BURSTABLE3,
        cdk.aws_ec2.InstanceSize.MICRO,
      ),
      credentials: rds.Credentials.fromSecret(dbCredentials),
      storageEncrypted: true,
      kmsKey: dbKmsKey,                      // ✅ Encryption at rest with CMK
      multiAz: true,
      backupRetention: Duration.days(35),
      deletionProtection: true,
      vpcSubnets: { subnetType: cdk.aws_ec2.SubnetType.PRIVATE_WITH_EGRESS },
      // Attach the role that has explicit KMS permissions
      associatedRoles: [{ role: rdsRole }],
    });

    // -----------------------------------------------------------------
    // 5️⃣  Enable CloudTrail data events for KMS (audit key usage)
    // -----------------------------------------------------------------
    const trail = new cloudtrail.Trail(this, 'SecurityTrail', {
      isMultiRegionTrail: true,
      includeGlobalServiceEvents: true,
      enableFileValidation: true,
    });

    trail.addEventSelector(
      [
        {
          readWriteType: cloudtrail.ReadWriteType.ALL,
          includeManagementEvents: false,
          dataResources: [
            {
              type: cloudtrail.DataResourceType.KMS_KEY,
              values: [dbKmsKey.keyArn],
            },
          ],
        },
      ],
      {
        // Forward to CloudWatch Logs for real‑time alerting
        cloudWatchLogGroup: new logs.LogGroup(this, 'KmsTrailLogGroup', {
          retention: logs.RetentionDays.NINETY_DAYS,
          encryptionKey: dbKmsKey, // encrypt logs with same CMK
        }),
      },
    );

    // -----------------------------------------------------------------
    // 6️⃣  Deploy Config rules to enforce key rotation & no wildcard principals
    // -----------------------------------------------------------------
    new config.ManagedRule(this, 'KmsKeyRotationEnabled', {
      identifier: 'KMS_KEY_ROTATION_ENABLED',
    });

    new config.ManagedRule(this, 'KmsKeyNoWildcardPrincipals', {
      identifier: 'KMS_KEY_NO_WILDCARD_PRINCIPALS',
    });

    // -----------------------------------------------------------------
    // 7️⃣  (Optional) GuardDuty integration – enable via console or CDK
    // -----------------------------------------------------------------
    // GuardDuty is a regional service; enabling it via CDK is not yet supported.
    // Ensure GuardDuty is turned on in each region and that the detector
    // includes the KMS data events from the CloudTrail above.
  }
}
```

