#### AWS CDK – VPC with S3 Gateway Endpoint & SG

```ts
import { Vpc, SubnetType, SecurityGroup, Peer, Port } from 'aws-cdk-lib/aws-ec2';
import { GatewayVpcEndpointAwsService } from 'aws-cdk-lib/aws-ec2';

const vpc = new Vpc(this, 'MobileAppVPC', {
  maxAzs: 2,
  subnetConfiguration: [{ name: 'app', subnetType: SubnetType.PRIVATE_WITH_EGRESS }],
});

const s3Endpoint = vpc.addGatewayEndpoint('S3Endpoint', {
  service: GatewayVpcEndpointAwsService.S3,
});

const appSG = new SecurityGroup(this, 'AppSG', {
  vpc,
  description: 'Allow only S3 endpoint traffic',
  allowAllOutbound: false,
});

appSG.addEgressRule(Peer.prefixList(s3Endpoint.prefixListId), Port.tcp(443), 'HTTPS to S3');
```

*Why this is safe*  
* `allowAllOutbound: false` forces explicit egress rules (CWE‑284).  
* Only the S3 prefix list is permitted, blocking arbitrary HTTPS destinations.

