## 1️⃣ Design‑time Controls

### 1.1 Use “declare‑once, enforce‑always” patterns in CDK

```ts
import * as cdk from 'aws-cdk-lib';
import { Construct } from 'constructs';
import * as s3 from 'aws-cdk-lib/aws-s3';
import * as iam from 'aws-cdk-lib/aws-iam';
import * as kms from 'aws-cdk-lib/aws-kms';
import * as logs from 'aws-cdk-lib/aws-logs';
import * as stepfunctions from 'aws-cdk-lib/aws-stepfunctions';
import * as tasks from 'aws-cdk-lib/aws-stepfunctions-tasks';

/**
 * SecureStack demonstrates atomic, ordered creation of resources.
 * All security controls are attached *before* the resource becomes usable.
 */
export class SecureStack extends cdk.Stack {
  constructor(scope: Construct, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // 1️⃣ Create a KMS key *first* – it will be used for all encryption.
    const dataKey = new kms.Key(this, 'DataKey', {
      enableKeyRotation: true,
      description: 'Key for encrypting S3 and RDS data',
      removalPolicy: cdk.RemovalPolicy.RETAIN, // Prevent accidental deletion
    });

    // 2️⃣ Create the S3 bucket with encryption *and* a restrictive bucket policy.
    const bucket = new s3.Bucket(this, 'SecureBucket', {
      encryption: s3.BucketEncryption.KMS,
      encryptionKey: dataKey,
      blockPublicAccess: s3.BlockPublicAccess.BLOCK_ALL,
      versioned: true,
      enforceSSL: true,
      removalPolicy: cdk.RemovalPolicy.RETAIN,
    });

    // 3️⃣ Attach a *least‑privilege* bucket policy *immediately*.
    bucket.addToResourcePolicy(new iam.PolicyStatement({
      actions: ['s3:GetObject', 's3:PutObject'],
      principals: [new iam.ServicePrincipal('lambda.amazonaws.com')],
      resources: [bucket.arnForObjects('*')],
      conditions: {
        // Enforce that calls come from a specific Lambda role
        StringEquals: { 'aws:PrincipalArn': this.lambdaRole.roleArn },
      },
    }));

    // 4️⃣ Define a Lambda role with the exact permissions needed.
    const lambdaRole = new iam.Role(this, 'SecureLambdaRole', {
      assumedBy: new iam.ServicePrincipal('lambda.amazonaws.com'),
      description: 'Role for the data‑processing Lambda',
      managedPolicies: [
        iam.ManagedPolicy.fromAwsManagedPolicyName('service-role/AWSLambdaBasicExecutionRole')
      ],
    });
    // Grant the role permission to use the KMS key – no broader access.
    dataKey.grantEncryptDecrypt(lambdaRole);

    // 5️⃣ Create the Lambda *after* the role and bucket are fully defined.
    const fn = new lambda.Function(this, 'SecureProcessor', {
      runtime: lambda.Runtime.NODEJS_20_X,
      handler: 'index.handler',
      code: lambda.Code.fromAsset('lambda'),
      role: lambdaRole,
      environment: {
        BUCKET_NAME: bucket.bucketName,
        KMS_KEY_ID: dataKey.keyId,
      },
      // Fail‑closed: do not allow the function to start if any required env var is missing.
      reservedConcurrentExecutions: 5, // limit blast radius
    });

    // 6️⃣ Step Functions workflow – enforce mandatory validation step.
    const validate = new tasks.LambdaInvoke(this, 'ValidateInput', {
      lambdaFunction: fn,
      payloadResponseOnly: true,
      resultPath: '$.validation',
    });

    const process = new tasks.LambdaInvoke(this, 'ProcessData', {
      lambdaFunction: fn,
      payloadResponseOnly: true,
      resultPath: '$.process',
    });

    // Enforce order: Validate → Process → (optional) Cleanup
    const definition = validate
      .next(process)
      .addCatch(new stepfunctions.Fail(this, 'ValidationFailed'), {
        errors: ['States.ALL'],
        resultPath: '$.errorInfo',
      });

    new stepfunctions.StateMachine(this, 'SecureStateMachine', {
      definition,
      logs: {
        destination: new logs.LogGroup(this, 'SFNLogGroup', {
          retention: logs.RetentionDays.ONE_WEEK,
          removalPolicy: cdk.RemovalPolicy.DESTROY,
        }),
        level: stepfunctions.LogLevel.ALL,
      },
      tracingEnabled: true,
    });
  }
}
```

#### Why this pattern mitigates CWE‑691

| Control | How it prevents out‑of‑order execution |
|---------|----------------------------------------|
| **KMS key created first** | Guarantees that any subsequent resource that references the key will have encryption enforced from the moment it exists. |
| **Bucket policy attached before bucket is used** | No window where the bucket is publicly accessible. |
| **Least‑privilege Lambda role** | The function cannot perform actions it was not explicitly granted, eliminating “privilege‑escalation via missing checks”. |
| **Step Functions explicit ordering** | The state machine definition is a directed acyclic graph; the `next()` call enforces that `ValidateInput` must succeed before `ProcessData` runs. |
| **Fail‑closed defaults** (`blockPublicAccess`, `enforceSSL`, `reservedConcurrentExecutions`) | If any required condition is missing, the resource fails to deploy or start, rather than silently proceeding. |

### 1.2 Policy‑as‑Code & CI/CD Guardrails

1. **Static analysis** – integrate **cfn‑nag**, **Checkov**, or **Bridgecrew** into the pipeline. Enforce rules such as:
