const responder = new lambda.Function(this, 'GuardDutyResponder', {
  runtime: lambda.Runtime.PYTHON_3.11,
  handler: 'handler.main',
  code: lambda.Code.fromAsset('lambda/guardduty_responder'),
  timeout: cdk.Duration.minutes(5),
  environment: {
    QUARANTINE_BUCKET: exfiltrationSinkBucket.bucketName,
  },
});

new events.Rule(this, 'GuardDutyFindingRule', {
  eventPattern: {
    source: ['aws.guardduty'],
    detailType: ['GuardDuty Finding'],
    detail: {
      type: [{ prefix: 'Exfiltration' }], // matches GuardDuty exfiltration findings
    },
  },
}).addTarget(new targets.LambdaFunction(responder));
