## 3.  Cloud‑Native Implementation Example (AWS CDK – TypeScript)

Below is a **minimal, production‑ready CDK construct** that enforces the hardening measures described above. The code is deliberately free of the following CWEs:

| CWE | Why it is avoided |
|-----|-------------------|
| CWE‑798 (Use of Hard‑coded Credentials) | All secrets are retrieved from **AWS Secrets Manager** at runtime. |
| CWE‑269 (Improper Privilege Management) | The IAM role is scoped to the exact actions and resources needed. |
| CWE‑200 (Information Exposure) | No logs are written to public buckets; CloudWatch log groups are encrypted with a KMS key. |
| CWE‑20 (Improper Input Validation) | The construct does not process external input; any user‑provided data must be validated upstream. |

```typescript
import * as cdk from 'aws-cdk-lib';
import { Construct } from 'constructs';
import * as ec2 from 'aws-cdk-lib/aws-ec2';
import * as iam from 'aws-cdk-lib/aws-iam';
import * as ssm from 'aws-cdk-lib/aws-ssm';
import * as logs from 'aws-cdk-lib/aws-logs';
import * as kms from 'aws-cdk-lib/aws-kms';
import * as guardduty from 'aws-cdk-lib/aws-guardduty';

export class Icsa2404608Hardening extends Construct {
  constructor(scope: Construct, id: string) {
    super(scope, id);

    // -----------------------------------------------------------------
    // 1. KMS key for log encryption (CWE‑311)
    // -----------------------------------------------------------------
    const logKey = new kms.Key(this, 'LogEncryptionKey', {
      enableKeyRotation: true,
      description: 'KMS key for encrypting CloudWatch logs of the OT service',
    });

    // -----------------------------------------------------------------
    // 2. VPC & Subnet layout (private subnet for OT service)
    // -----------------------------------------------------------------
    const vpc = new ec2.Vpc(this, 'Otvpc', {
      maxAzs: 2,
      subnetConfiguration: [
        {
          name: 'PrivateOT',
          subnetType: ec2.SubnetType.PRIVATE_WITH_EGRESS,
          cidrMask: 24,
        },
        {
          name: 'PublicMgmt',
          subnetType: ec2.SubnetType.PUBLIC,
          cidrMask: 24,
        },
      ],
    });

    // -----------------------------------------------------------------
    // 3. Security Group – whitelist only management hosts
    // -----------------------------------------------------------------
    const otSg = new ec2.SecurityGroup(this, 'OTServiceSG', {
      vpc,
      description: 'Allow OT management traffic only',
      allowAllOutbound: true,
    });

    // Example: allow traffic from a known management SG (replace with real ID)
    const mgmtSgId = cdk.Fn.importValue('MgmtSecurityGroupId');
    otSg.addIngressRule(
      ec2.SecurityGroup.fromSecurityGroupId(this, 'MgmtSG', mgmtSgId),
      ec2.Port.tcp(443), // TLS‑only
      'Allow TLS from management stations'
    );

    // -----------------------------------------------------------------
    // 4. IAM Role – least privilege for the OT service
    // -----------------------------------------------------------------
    const otRole = new iam.Role(this, 'OTServiceRole', {
      assumedBy: new iam.ServicePrincipal('ec2.amazonaws.com'),
      description: 'Least‑privilege role for the patched OT service',
    });

    // Example permissions – adjust to actual needs
    otRole.addToPolicy(
      new iam.PolicyStatement({
        actions: ['s3:GetObject'],
        resources: ['arn:aws:s3:::ot-config-bucket/*'],
        effect: iam.Effect.ALLOW,
      })
    );

    // -----------------------------------------------------------------
    // 5. EC2 Instance – runs the patched binary
    // -----------------------------------------------------------------
    const otInstance = new ec2.Instance(this, 'OTInstance', {
      vpc,
      vpcSubnets: { subnetType: ec2.SubnetType.PRIVATE_WITH_EGRESS },
      securityGroup: otSg,
      instanceType: ec2.InstanceType.of(
        ec2.InstanceClass.C5,
        ec2.InstanceSize.LARGE
      ),
      machineImage: ec2.MachineImage.genericLinux({
        // AMI must be pre‑hardened and contain the patched binary
        'us-east-1': ssm.StringParameter.valueForStringParameter(
          this,
          '/ami/ot-service/patched'
        ),
      }),
      role: otRole,
      keyName: cdk.Fn.importValue('OpsKeyPair'), // never hard‑code keys
    });

    // -----------------------------------------------------------------
    // 6. CloudWatch Log Group – encrypted, retention 90 days
    // -----------------------------------------------------------------
    const logGroup = new logs.LogGroup(this, 'OTLogGroup', {
      retention: logs.RetentionDays.NINETY_DAYS,
      encryptionKey: logKey,
      removalPolicy: cdk.RemovalPolicy.RETAIN,
    });

    // -----------------------------------------------------------------
    // 7. GuardDuty Custom Threat List – add advisory IoCs
    // -----------------------------------------------------------------
    const gd = guardduty.CfnDetector.new(this, 'GuardDutyDetector', {
      enable: true,
    });

    const iocs = new guardduty.CfnThreatIntelSet(this, 'ICSA2404608IoCs', {
      activate: true,
      detectorId: gd.ref,
      format: 'TXT',
      location: 's3://icad-iocs-bucket/icsa-2404608-iocs.txt',
      name: 'ICSA-24-046-08 IoCs',
    });

    // -----------------------------------------------------------------
    // 8. Config Rule – enforce SG and IAM constraints
    // -----------------------------------------------------------------
    new cdk.aws_config.ManagedRule(this, 'RestrictOTSG', {
      identifier: 'INCOMING_SSH_DISABLED', // example rule; replace with custom rule if needed
    });

    // -----------------------------------------------------------------
    // 9. Tagging for inventory & automation
    // -----------------------------------------------------------------
    cdk.Tags.of(otInstance).add('cisa:icsa-24-046-08', 'affected');
    cdk.Tags.of(otSg).add('cisa:icsa-24-046-08', 'protected');
  }
}
```

